You are a senior code reviewer doing a second independent review pass. Focus on different angles than a typical first review.

## Files to review

### packages/core/src/transcript/db.ts — key functions

```ts
// migrateSchema: adds content + commit_layer columns to existing DB
function migrateSchema(db): void {
  for (const col of ['content', 'commit_layer']) {
    try {
      db.exec(`ALTER TABLE transcripts ADD COLUMN ${col} TEXT NOT NULL DEFAULT ''`)
    } catch (e) {
      if (!(e instanceof Error) || !e.message.includes('duplicate column name')) throw e
    }
  }
}

// migrateFts: drops+recreates FTS table if commit_layer column missing
function migrateFts(db): void {
  const row = db.prepare(
    "SELECT sql FROM sqlite_master WHERE type='table' AND name='transcripts_fts'"
  ).get() as { sql: string } | undefined
  if (!row || !row.sql.includes('commit_layer')) {
    db.exec('DROP TABLE IF EXISTS transcripts_fts')
    db.exec(CREATE_FTS_SQL)
    db.exec(REBUILD_FTS_SQL)
  }
}

// searchTranscriptsByColumns: column-scoped FTS4 MATCH
export function searchTranscriptsByColumns(dbPath, query, columns, limit = 20): SearchResult[] {
  const sanitized = sanitizeFtsQuery(query)
  if (!sanitized || columns.length === 0) return []
  if (!existsSync(dbPath)) return []
  const columnQuery = columns.map((col) => `${col}:${sanitized}`).join(' OR ')
  const db = new Database(dbPath, { readonly: true })
  try {
    return db.prepare(SEARCH_SQL).all(columnQuery, limit) as SearchResult[]
  } catch { return [] } finally { db.close() }
}

// upsertSearchIndex: write path
export function upsertSearchIndex(dbPath, manifest): void {
  const db = openDb(dbPath)
  try {
    db.exec(CREATE_TABLE_SQL)
    migrateSchema(db)
    db.exec(CREATE_FTS_SQL)
    migrateFts(db)
    const params = ALL_COLUMNS.map((col) => {
      const value = record[col]
      if (value === undefined || value === null) return ''
      return typeof value === 'number' ? value : String(value)
    })
    db.prepare(UPSERT_SQL).run(params)
    db.exec(REBUILD_FTS_SQL)
  } finally { db.close() }
}
```

### packages/core/src/recall/recall.ts — searchRecall

```ts
export function searchRecall(globalRoot, query, limit = 20): SearchRecallResult {
  const dbPath = join(globalRoot, 'index', 'search.sqlite')
  const layer1 = searchTranscriptsByColumns(dbPath, query, ['commit_layer'], limit)
  if (layer1.length > 0) return { layer: 1, results: layer1 }
  const layer2 = searchTranscripts(dbPath, query, limit)
  if (layer2.length > 0) return { layer: 2, results: layer2 }
  const layer3 = searchTranscriptsByColumns(dbPath, query, ['content'], limit)
  return { layer: 3, results: layer3 }
}
```

### packages/core/src/storage/factory.ts

```ts
export function createVectorAdapter(cfg: StorageConfig): VectorAdapter {
  if (cfg.vector_backend === 'qdrant') {
    return new QdrantVectorAdapter(...)  // throws "not implemented in Phase 1"
  }
  throw new Error('sqlite-vec VectorAdapter not implemented in Phase 1')
}

export function createGraphAdapter(cfg: StorageConfig): GraphAdapter {
  if (cfg.graph_backend === 'neo4j') {
    return new Neo4jGraphAdapter(...)  // throws "not implemented in Phase 1"
  }
  throw new Error('sqlite GraphAdapter not implemented in Phase 1')
}
```

### packages/core/src/storage/search/sqlite-fts-adapter.ts

```ts
export class SqliteFtsAdapter implements SearchAdapter {
  constructor(private readonly dbPath: string) {}
  search(query, options = {}): SearchResult[] {
    return searchTranscripts(this.dbPath, query, options.limit ?? 20)
  }
  upsert(manifest): void { upsertSearchIndex(this.dbPath, manifest) }
  close(): void {}
}
```

### packages/core/src/transcript/import.ts (upsert section)

```ts
try {
  const contentText = readFileSync(globalCleanPath, 'utf-8')
  upsertSearchIndex(globalDbPath, { ...manifest, content: contentText, commit_layer: '' })
} catch {
  // Non-fatal
}
```

## Review focus — second pass angles
1. Concurrency / race conditions (multiple processes writing same DB)
2. Migration correctness under failure scenarios (partial migration, crash mid-migration)
3. FTS4 column filter syntax correctness — does `col:term OR col2:term` actually work in SQLite FTS4?
4. content field size — clean markdown can be large (100KB+). Any SQLite limits? Performance impact on FTS rebuild?
5. searchRecall layer logic — are there cases where layer2 and layer3 return overlapping results? Is that a problem?
6. Factory design — is it correct that createVectorAdapter always throws for Phase 1? Will this break any existing callers?
7. Test gaps — what important scenarios are NOT tested?

Be specific: file + section + issue + severity (CRITICAL/HIGH/MEDIUM/LOW).
Skip style issues.

